const payload = $input.first().json;

// Recursive function to deeply search the JSON for text and phone number
function findDeep(obj, targetKeys) {
  let result = {};
  if (!obj || typeof obj !== 'object') return result;

  for (const [k, v] of Object.entries(obj)) {
    if (targetKeys.includes(k) && (typeof v === 'string' || typeof v === 'number')) {
      result[k] = String(v);
    }
    if (typeof v === 'object') {
      Object.assign(result, findDeep(v, targetKeys));
    }
  }
  return result;
}

// Look for common keys that contain the message and phone number
const found = findDeep(payload, ['body', 'text', 'message', 'from', 'waId', 'wa_id', 'sender', 'recipientPhoneNumber', 'display_phone_number']);

// Get text: try .body first (from Meta's text.body), then .text, then .message
let text = '';
if (payload.text && typeof payload.text === 'object' && payload.text.body) {
  text = payload.text.body;
} else if (payload.message && typeof payload.message === 'object' && payload.message.text && payload.message.text.body) {
  text = payload.message.text.body;
} else {
  text = found.body || found.text || found.message || '';
}

// Get phone number
let from = found.from || found.wa_id || found.waId || found.sender || '';

const skip = (!text || !from) ? true : false;

return [{
  json: {
    skip: skip,
    phone_number: from,
    message_text: text,
    message_type: 'text',
    debug_raw: payload
  }
}];
